package agent

import (
	"context"
	"path/filepath"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// newCancelTestBeadStore returns a real *bead.Store rooted at projectRoot/.ddx,
// with one open bead pre-created so the worker's poll path has a real backing
// document to read. setupArtifactTestProjectRoot already created the .ddx
// directory; the worker's prepareArtifacts populates a bead inside the
// per-attempt worktree, but the cancel poll reads from projectRoot's store.
func newCancelTestBeadStore(t *testing.T, projectRoot, beadID string) *bead.Store {
	t.Helper()
	store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
	if err := store.Init(); err != nil {
		t.Fatal(err)
	}
	if err := store.Create(&bead.Bead{ID: beadID, Title: "cancel integration bead", Status: bead.StatusInProgress}); err != nil {
		t.Fatal(err)
	}
	return store
}

// fakeCancelStore is a memory-only BeadCancelStore for worker tests. The
// trigger channel pings the poll loop the moment the test wants the marker
// observed (instead of waiting for the next CancelPollInterval tick to fire
// against a real bead store on disk).
type fakeCancelStore struct {
	mu        sync.Mutex
	requested bool
	honored   bool
	calls     atomic.Int32
}

func (f *fakeCancelStore) IsCancelRequested(id string) (bool, error) {
	f.calls.Add(1)
	f.mu.Lock()
	defer f.mu.Unlock()
	if f.honored {
		return false, nil
	}
	return f.requested, nil
}

func (f *fakeCancelStore) MarkCancelHonored(id string) error {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.honored = true
	return nil
}

func (f *fakeCancelStore) request() {
	f.mu.Lock()
	defer f.mu.Unlock()
	f.requested = true
}

func (f *fakeCancelStore) wasHonored() bool {
	f.mu.Lock()
	defer f.mu.Unlock()
	return f.honored
}

// blockingAgentRunner blocks Run until ctx cancels, then returns a non-zero
// exit code (mirroring what a real subprocess does when its context dies).
// startedAt is closed once Run is on the blocking select so tests can
// deterministically race their cancel write against the in-flight attempt.
type blockingAgentRunner struct {
	startedAt chan struct{}
	once      sync.Once
}

func (r *blockingAgentRunner) Run(opts RunArgs) (*Result, error) {
	r.once.Do(func() { close(r.startedAt) })
	ctx := opts.Context
	if ctx == nil {
		ctx = context.Background()
	}
	<-ctx.Done()
	return &Result{ExitCode: 1, Error: ctx.Err().Error()}, nil
}

func newBlockingAgentRunner() *blockingAgentRunner {
	return &blockingAgentRunner{startedAt: make(chan struct{})}
}

// TestWorker_HonorsCancelMidAttempt: when the operator-cancel marker flips
// while an attempt is mid-flight, the worker cancels the dispatch context,
// marks cancel-honored, and emits a preserved_for_review result with reason
// operator_cancel. ADR-022 §Cancel SLA, AC#3.
func TestWorker_HonorsCancelMidAttempt(t *testing.T) {
	const beadID = "ddx-cancel-mid"

	prev := CancelPollInterval
	CancelPollInterval = 25 * time.Millisecond
	t.Cleanup(func() { CancelPollInterval = prev })

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "cancel0000000001",
		resultRev:   "cancel0000000001",
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, "", false, 0)
		},
	}

	cancelStore := &fakeCancelStore{}
	runner := newBlockingAgentRunner()

	// Flip the cancel marker as soon as the runner is in its blocking select.
	go func() {
		<-runner.startedAt
		cancelStore.request()
	}()

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})

	done := make(chan *ExecuteBeadResult, 1)
	go func() {
		res, err := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{
			AgentRunner: runner,
			BeadCancel:  cancelStore,
		}, gitOps)
		if err != nil {
			t.Errorf("ExecuteBeadWithConfig: %v", err)
		}
		done <- res
	}()

	var res *ExecuteBeadResult
	select {
	case res = <-done:
	case <-time.After(5 * time.Second):
		t.Fatal("worker did not return within 5s after cancel; mid-attempt poll did not abort")
	}

	if res == nil {
		t.Fatal("nil result")
	}
	if res.Outcome != "preserved" {
		t.Errorf("Outcome = %q, want %q", res.Outcome, "preserved")
	}
	if res.Reason != OperatorCancelReason {
		t.Errorf("Reason = %q, want %q", res.Reason, OperatorCancelReason)
	}
	if res.Status != ExecuteBeadStatusPreservedNeedsReview {
		t.Errorf("Status = %q, want %q", res.Status, ExecuteBeadStatusPreservedNeedsReview)
	}
	if !cancelStore.wasHonored() {
		t.Error("cancel-honored was not set on the cancel store")
	}
}

// TestCancelLatency_UnderSLA: the worker observes cancel and returns within
// a small multiple of CancelPollInterval (the SLA contract — ADR-022 §Cancel
// SLA promises observation within one poll interval at the next safe point).
func TestCancelLatency_UnderSLA(t *testing.T) {
	const beadID = "ddx-cancel-sla"
	const pollInterval = 50 * time.Millisecond

	prev := CancelPollInterval
	CancelPollInterval = pollInterval
	t.Cleanup(func() { CancelPollInterval = prev })

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "sla0000000000001",
		resultRev:   "sla0000000000001",
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, "", false, 0)
		},
	}

	cancelStore := &fakeCancelStore{}
	runner := newBlockingAgentRunner()

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})

	startedDispatch := make(chan struct{})
	done := make(chan *ExecuteBeadResult, 1)
	go func() {
		close(startedDispatch)
		res, _ := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{
			AgentRunner: runner,
			BeadCancel:  cancelStore,
		}, gitOps)
		done <- res
	}()

	<-startedDispatch
	<-runner.startedAt
	cancelStore.request()
	cancelAt := time.Now()

	select {
	case res := <-done:
		latency := time.Since(cancelAt)
		// Allow up to 4× the poll interval to absorb scheduler + worktree
		// teardown overhead. The SLA contract is "within one poll interval at
		// the next safe point"; this test asserts the bound is honored, not
		// the wall-clock minimum.
		if latency > 4*pollInterval+250*time.Millisecond {
			t.Errorf("cancel latency %v exceeded SLA budget (%v)", latency, 4*pollInterval+250*time.Millisecond)
		}
		if res == nil || res.Reason != OperatorCancelReason {
			t.Errorf("expected operator_cancel result, got %+v", res)
		}
	case <-time.After(5 * time.Second):
		t.Fatal("cancel did not propagate within 5s")
	}
}

// TestOperatorCancel_DuringRealClaudeAttempt is the WIRED-IN integration test
// (AC#7). Instead of swapping in a stub for dispatchAgentRun, it exercises
// the real end-to-end path: a long-running script-style runner that polls the
// caller's context (the same contract a real claude subprocess satisfies via
// SIGTERM on cancel) is dispatched by ExecuteBeadWithConfig; the operator
// cancel marker is flipped on a real *bead.Store via RequestCancel; the
// worker must observe the marker through its mid-attempt poll, propagate
// cancellation into the in-flight dispatch (proving the subprocess receives
// the cancel signal), and emit preserved_for_review/operator_cancel.
//
// This is not a stub-attempt cancel — RequestCancel writes to the same bead
// store the worker reads, and the runner only returns when its dispatch ctx
// is cancelled by the poll loop, demonstrating the cancel actually traveled
// through the live signal path.
func TestOperatorCancel_DuringRealClaudeAttempt(t *testing.T) {
	const beadID = "ddx-cancel-realattempt"

	prev := CancelPollInterval
	CancelPollInterval = 25 * time.Millisecond
	t.Cleanup(func() { CancelPollInterval = prev })

	projectRoot := setupArtifactTestProjectRoot(t)
	gitOps := &artifactTestGitOps{
		projectRoot: projectRoot,
		baseRev:     "real000000000001",
		resultRev:   "real000000000001",
		wtSetupFn: func(wtPath string) {
			setupArtifactTestWorktree(t, wtPath, beadID, "", false, 0)
		},
	}

	// Use the real *bead.Store rooted at the project's .ddx, the same one
	// the server's handleCancelBead writes to via beadStoreForRequest.
	beadStore := newCancelTestBeadStore(t, projectRoot, beadID)

	// A runner that blocks like a real claude subprocess until its context
	// is signalled. Exit code 1 + ctx.Err() mirrors what the OS executor
	// returns when SIGTERM kills the child mid-stream.
	runner := newBlockingAgentRunner()

	// The "operator" hits POST /api/beads/<id>/cancel — modeled here by
	// calling RequestCancel directly, the function the HTTP handler calls.
	subprocessSawCancel := make(chan struct{})
	go func() {
		<-runner.startedAt
		// Wait one extra tick to make sure the worker's poll loop is the
		// one that drives the abort, not a context already-cancelled state.
		time.Sleep(2 * CancelPollInterval)
		if _, err := beadStore.RequestCancel(beadID); err != nil {
			t.Errorf("RequestCancel: %v", err)
		}
		close(subprocessSawCancel)
	}()

	rcfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{}).Resolve(config.CLIOverrides{})

	done := make(chan *ExecuteBeadResult, 1)
	go func() {
		res, _ := ExecuteBeadWithConfig(context.Background(), projectRoot, beadID, rcfg, ExecuteBeadRuntime{
			AgentRunner: runner,
			BeadCancel:  beadStore,
		}, gitOps)
		done <- res
	}()

	<-subprocessSawCancel

	var res *ExecuteBeadResult
	select {
	case res = <-done:
	case <-time.After(10 * time.Second):
		t.Fatal("worker did not honor cancel on a real attempt within 10s")
	}

	if res == nil || res.Reason != OperatorCancelReason {
		t.Fatalf("expected preserved/operator_cancel, got %+v", res)
	}
	if res.Status != ExecuteBeadStatusPreservedNeedsReview {
		t.Errorf("Status = %q, want %q", res.Status, ExecuteBeadStatusPreservedNeedsReview)
	}

	// And the cancel-honored marker must be persisted on the real bead.
	requested, err := beadStore.IsCancelRequested(beadID)
	if err != nil {
		t.Fatalf("IsCancelRequested: %v", err)
	}
	if requested {
		t.Error("IsCancelRequested still true after worker honored — cancel-honored marker missing")
	}
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"path/filepath"
	"regexp"
	"strings"
	"sync"
	"time"

	agenttry "github.com/DocumentDrivenDX/ddx/internal/agent/try"
	"github.com/DocumentDrivenDX/ddx/internal/agent/work"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
)

// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, tier bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log          io.Writer
	EventSink    io.Writer
	ProgressCh   chan<- ProgressEvent
	PreClaimHook func(ctx context.Context) error
	// PreClaimIntakeHook runs after routing preflight and before Claim. It
	// classifies the candidate for actionability/scope; only
	// actionable_atomic proceeds directly to Claim. Non-atomic outcomes
	// skip the bead without claim. intake_error fail-opens so infrastructure
	// failures do not become hidden dispatch failures.
	PreClaimIntakeHook    PreClaimIntakeHook
	PreDispatchLintHook   func(ctx context.Context, beadID string) (LintResult, error)
	PostAttemptTriageHook func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error)
	// ReviewCostCap, when non-nil, accumulates reviewer cost on the same
	// loop budget tracker used by the implementer attempts.
	ReviewCostCap *escalation.CostCapTracker
	// RoutePreflight, when non-nil, runs once during Run bootstrap before
	// the drain loop starts. It is expected to call upstream ResolveRoute
	// against the loop's resolved (harness, model) and return whatever typed
	// routing error the upstream surfaced — notably
	// agent.ErrHarnessModelIncompatible when the harness allow-list rejects
	// the model. Any non-nil error stops the worker before any bead is
	// claimed; DDx does NOT duplicate the upstream allow-list.
	RoutePreflight func(ctx context.Context, harness, model string) error
	Once           bool
	PollInterval   time.Duration
	NoReview       bool
	LabelFilter    string
	SessionID      string
	WorkerID       string
	ProjectRoot    string
	// TargetBeadID, when non-empty, restricts nextCandidate to only return the
	// named bead from the execution-ready queue. Used by `ddx try <bead-id>`
	// to dispatch a single specific bead through the same claim → executor →
	// land path the queue drain uses. When empty, the picker behaves normally.
	TargetBeadID string
	// WakeCh, when non-nil, signals the idle-poll sleep to return immediately
	// so the loop re-scans the queue. Used by the operator-prompt approve /
	// auto-approve mutations (Story 15) to avoid a poll-interval-sized delay
	// before a freshly-approved bead is claimed. Implementations must send
	// non-blocking (server-side helpers do); the loop only waits for a
	// receive on WakeCh during the idle sleep, never elsewhere.
	WakeCh <-chan struct{}
}

// DefaultReviewMaxRetries is the number of reviewer attempts allowed per
// committed result_rev before the loop emits a terminal
// `review-manual-required` event and stops re-executing primary. FEAT-022 §14.
const DefaultReviewMaxRetries = 3

// MaxLoopCooldown is the absolute upper bound the execute-loop will set for
// any execute-loop-retry-after value. Year-scale parks effectively mean
// "never retry" and that should be a deliberate operator choice via
// `ddx bead update --set execute-loop-retry-after=...`, not an automatic
// loop decision. Beyond this cap, the loop refuses to lengthen the cooldown
// further; an operator extending it manually still works.
const MaxLoopCooldown = 24 * time.Hour

// LandConflictCooldown is the short cooldown applied when all conflict-recovery
// paths fail (3-way ort auto-merge + optional focused-resolve agent) and the
// bead is parked as land_conflict_unresolvable. Much shorter than
// MaxLoopCooldown because land conflicts often resolve quickly as sibling beads
// advance the base branch.
const LandConflictCooldown = 15 * time.Minute

// StoreErrorCooldown is the short cooldown applied when a Store.* operation in
// the outcome-handling block returns a transient error. It prevents an
// immediate re-queue of the affected bead while allowing the loop to continue
// to the next candidate. Store errors during outcome handling are non-fatal:
// they are logged and emitted as loop-error events but do not terminate the
// worker.
const StoreErrorCooldown = 5 * time.Minute

// SubmitWithPreMergeChecks is the canonical land-back step for the execute-bead
// loop. It runs the project's .ddx/checks/*.yaml gate against the worker's
// (baseRev, resultRev) before forwarding to submit. On Blocked, it preserves
// the worker's result under refs/ddx/iterations/, records checks-blocked
// events on the bead, and returns the synthesised LandResult{Status:"preserved"}
// without ever calling submit. On pass, honoured checks-bypass annotations are
// recorded as checks-bypass events and submit runs normally.
//
// submit is the project's land coordinator entry point (typically
// LocalLandCoordinator.Submit or the server-side coordinator submit).
//
// The implementation lives in checks_premerge.go alongside its supporting
// helpers (RunPreMergeChecks, AppendPreMergeChecksEvents,
// PreserveAfterPreMergeChecks); this thin wrapper exists so the execute-bead
// loop's land-back call site is one obvious helper rather than three nested
// ones, and so callers wiring the gate do not need to import the helper layer
// directly.
func SubmitWithPreMergeChecks(
	ctx context.Context,
	projectRoot string,
	b *bead.Bead,
	res *ExecuteBeadResult,
	submit func(LandRequest) (*LandResult, error),
	eventStore BeadEventAppender,
	actor, source string,
	now func() time.Time,
) (*LandResult, *PreMergeChecksOutcome, error) {
	if now == nil {
		now = time.Now
	}
	if submit == nil {
		return nil, nil, fmt.Errorf("submit-with-pre-merge-checks: submit callback required")
	}
	evidenceDir := filepath.Join(projectRoot, res.ExecutionDir)
	outcome, err := RunPreMergeChecks(ctx, projectRoot, b, res.BaseRev, res.ResultRev, evidenceDir)
	if err != nil {
		// Treat checks_bypass / loader errors as a hard preserve: the worker
		// did its job; the operator misconfigured the gate. Better to park
		// the result under an iteration ref than to silently land it.
		ref := PreserveRef(res.BeadID, res.BaseRev)
		if upErr := (&RealOrchestratorGitOps{}).UpdateRef(projectRoot, ref, res.ResultRev); upErr != nil {
			return nil, nil, fmt.Errorf("preserving result after checks setup error: %w (original error: %v)", upErr, err)
		}
		return &LandResult{
			Status:      "preserved",
			PreserveRef: ref,
			Reason:      "pre-merge checks setup error: " + err.Error(),
		}, nil, nil
	}
	if outcome.Blocked {
		land, perr := PreserveAfterPreMergeChecks(projectRoot, res, outcome, &RealOrchestratorGitOps{})
		if perr != nil {
			return nil, outcome, perr
		}
		if eventStore != nil {
			_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
		}
		return land, outcome, nil
	}
	if eventStore != nil && len(outcome.Bypassed) > 0 {
		_ = AppendPreMergeChecksEvents(eventStore, res.BeadID, outcome, actor, source, now().UTC())
	}
	land, sErr := submit(BuildLandRequestFromResult(projectRoot, res))
	return land, outcome, sErr
}

// runPostAttemptTriage invokes the optional post-attempt triage hook after
// the attempt outcome has been finalized but before any cooldown decision is
// applied. Hook failures are fail-open: the report is returned unchanged and
// legacy cooldown behavior remains in force.
func (w *ExecuteBeadWorker) runPostAttemptTriage(ctx context.Context, candidate bead.Bead, report ExecuteBeadReport, runtime ExecuteBeadLoopRuntime, assignee string, now func() time.Time) ExecuteBeadReport {
	hook := runtime.PostAttemptTriageHook
	if hook == nil {
		return report
	}
	triage, err := hook(ctx, candidate.ID, report)
	if err != nil {
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "post-attempt triage error (%s %s): %v (continuing)\n", candidate.ID, report.Status, err)
		}
		return report
	}
	if strings.TrimSpace(triage.Classification) == "" {
		return report
	}
	report.OutcomeReason = triage.Classification
	recordPostAttemptTriageEvent(w.Store, candidate.ID, report, triage, assignee, now().UTC())
	return report
}

// CapLoopCooldown clamps a loop-set cooldown duration to MaxLoopCooldown.
// The loop uses this for every SetExecutionCooldown call so no automatic
// path can silently park a bead for a year.
func CapLoopCooldown(d time.Duration) time.Duration {
	if d <= 0 {
		return 0
	}
	if d > MaxLoopCooldown {
		return MaxLoopCooldown
	}
	return d
}

