			delete(b.Extra, "claimed-pid")
			delete(b.Extra, "claimed-machine")
			delete(b.Extra, "claimed-session")
			delete(b.Extra, "claimed-worktree")
			delete(b.Extra, "execute-loop-heartbeat-at")
		}
	}); err != nil {
		return err
	}
	return s.RemoveClaimHeartbeat(id)
}

